+            ids.items[write_pos] = new_id;
+            write_pos += 1;
+            read_pos += 2; // Skip both tokens
+        } else {
+            ids.items[write_pos] = ids.items[read_pos];
+            write_pos += 1;
+            read_pos += 1;
+        }
+    }
+
+    // Truncate to write_pos
+    ids.items.len = write_pos;
+    _ = allocator; // Suppress unused warning
